using namespace std;

long long solve(vector<long long> value, vector<long long> limit) {
    int n = value.size();
    vector<pair<long long, long long>> elements;
    for (int i = 0; i < n; ++i) {
        elements.emplace_back(limit[i], value[i]);
    }
    sort(elements.begin(), elements.end(), [](const pair<long long, long long>& a, const pair<long long, long long>& b) {
        return a.first < b.first;
    });

    long long res = 0;
    long long active = 0;
    for (int i = 0; i < n; ) {
        long long current_limit = elements[i].first;
        long long sum = 0;
        int j = i;
        while (j < n && elements[j].first == current_limit) {
            sum += elements[j].second;
            j++;
        }
        if (active < current_limit) {
            long long can_take = min((long long)(j - i), current_limit - active);
            sort(elements.begin() + i, elements.begin() + j, [](const pair<long long, long long>& a, const pair<long long, long long>& b) {
                return a.second > b.second;
            });
            for (int k = i; k < i + can_take; ++k) {
                res += elements[k].second;
            }
            active += can_take;
        }
        i = j;
    }
    return res;
}

